/*▄────────────────────▄
  █                    █
  █  Загрузка модулей  █
  █                    █
  ▀────────────────────▀*/
require('core'); // Ядро
const { Sender } = require('..'); // Работа с RAW-пакетами на уровне L2

/*┌────────────────────┐
  │ Создаем передатчик │
  └────────────────────┘*/
const sender = new Sender({
    iface:    'eth0', // Имя интерфейса
    delay:      1000, // Задержка между пакетами   = 1 сек
    delayError: 3000, // Задержка после ошибки     = 3 сек
    timeout:    5000  // Время на получение пакета = 5 сек
});

/*┌────────────────────────────────────────┐
  │ Добавляем обработчик обновления пакета │
  └────────────────────────────────────────┘*/
sender.on('updatePacket', (packet) => {
    _=['Пакет обновлен: ', packet.length, ' (update)'].join('')
    _=packet.toString('hex')
});

/*┌───────────────────────────────────────┐
  │ Добавляем обработчик отправки пакетов │
  └───────────────────────────────────────┘*/
sender.on('data', (packet) => {
    _=['Пакет отправлен: ', packet.length, ' (send)'].join('')
    _=packet.toString('hex')
});

/*┌─────────────────────────────┐
  │ Добавляем обработчик ошибок │
  └─────────────────────────────┘*/
sender.on('error', (err) => {
    _='Ошибка!'
    _=err
});

/*┌──────────────────────────────┐
  │ Добавляем обработчик запуска │
  └──────────────────────────────┘*/
sender.on('start', (isStartPacket) => {
    _='Запуск!'
    
    if (!isStartPacket) {
        _='Стартовый пакет еще не задан!'
    }
});

/*┌────────────────────────────────┐
  │ Добавляем обработчик остановки │
  └────────────────────────────────┘*/
sender.on('stop', () => {
    _='Остановка!'
});

/*┌──────────────────────────────────────────┐
  │ Обработчик аварийного завершения воркера │
  └──────────────────────────────────────────┘*/
sender.on('exit', (code) => {
    _=['Аварийное завершение воркера! Код выхода: ', code].join('')
});

/*┌──────────────────────────────────┐
  │ Добавляем обработчик перезапуска │
  └──────────────────────────────────┘*/
sender.on('restart', (reason) => {
    _=['Перезапуск передатчика... Причина: ', reason].join('')
});

/*┌───────────────────────────────┐
  │ Добавляем обработчик таймаута │
  └───────────────────────────────┘*/
sender.on('timeout', () => {
    _='Превышено время на отправку пакета!'
});

/*┌────────────────────────────────────────┐
  │ Обновляем пакет для следующей отправки │
  └────────────────────────────────────────┘*/
setTimeout(f => {
    sender.updatePacket(Buffer.from('1122334455667788', 'hex'));
}, 0);
